#include <iostream>
#include <string>
#include <vector>
#include <sstream>

extern bool isPalindromeSolution(const std::string& s);

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases_data = {
        {"", "The string is a palindrome."},
        {"!", "The string is a palindrome."},
        {"A", "The string is a palindrome."},
        {"Racecar", "The string is a palindrome."},
        {"Hello", "The string is not a palindrome."},
        {"Madam, I'm Adam", "The string is a palindrome."},
        {"A man, a plan, a canal: Panama", "The string is a palindrome."}
    };

    for (const auto& tc : test_cases_data) {
        bool result = isPalindromeSolution(tc.first);
        std::string output_message = result ? "The string is a palindrome." : "The string is not a palindrome.";
        std::cout << output_message << std::endl;
    }

    return 0;
}
